```java
import javax.swing.*;
import java.awt.*;
import java.awt.event.*;

public class SimpleCalc extends JFrame implements ActionListener {
    JTextField tfNum1, tfNum2, tfResult;
    JButton btnAdd, btnSub, btnEq;

    SimpleCalc() {
        setTitle("Simple Calculator");
        setSize(350, 150);
        setLayout(new BorderLayout(10, 10));
        setDefaultCloseOperation(EXIT_ON_CLOSE);

        // --- Top: two input fields ---
        JPanel top = new JPanel(new FlowLayout());
        tfNum1 = new JTextField(8);
        tfNum2 = new JTextField(8);
        top.add(new JLabel("A:"));
        top.add(tfNum1);
        top.add(new JLabel("B:"));
        top.add(tfNum2);

        // --- Center: operator + equals button ---
        JPanel mid = new JPanel(new FlowLayout());
        btnAdd = new JButton("+");
        btnSub = new JButton("-");
        btnEq  = new JButton("=");
        btnAdd.addActionListener(this);
        btnSub.addActionListener(this);
        btnEq.addActionListener(this);
        mid.add(btnAdd); mid.add(btnSub); mid.add(btnEq);

        // --- Bottom: result field ---
        tfResult = new JTextField(15);
        tfResult.setEditable(false);
        JPanel bot = new JPanel(new FlowLayout());
        bot.add(new JLabel("Result:"));
        bot.add(tfResult);

        add(top,  BorderLayout.NORTH);
        add(mid,  BorderLayout.CENTER);
        add(bot,  BorderLayout.SOUTH);

        setVisible(true);
    }

    String op = "";   // remembers the chosen operator

    public void actionPerformed(ActionEvent e) {
        Object src = e.getSource();
        if (src == btnAdd) op = "+";
        else if (src == btnSub) op = "-";
        else if (src == btnEq) {
            try {
                double a = Double.parseDouble(tfNum1.getText());
                double b = Double.parseDouble(tfNum2.getText());
                double r = op.equals("+") ? (a + b) : (a - b);
                tfResult.setText(String.valueOf(r));
            } catch (NumberFormatException ex) {
                tfResult.setText("Invalid Input");
            }
        }
    }

    public static void main(String[] args) { new SimpleCalc(); }
}
```

