        btnSubmit.addActionListener(this);

        // --- Result area inside a scroll pane ---
        taResult = new JTextArea(6, 30);
        taResult.setEditable(false);
        JScrollPane sp = new JScrollPane(taResult);

        add(pChecks); add(pRate); add(btnSubmit); add(sp);
