    public void actionPerformed(ActionEvent e) {
        StringBuilder feedback = new StringBuilder("Feedback Topics:\n");
        if (cbQuality.isSelected()) feedback.append("  • Product Quality\n");
        if (cbService.isSelected()) feedback.append("  • Customer Service\n");
        if (cbPrice.isSelected())   feedback.append("  • Pricing\n");
