### 3.5 Derivation 4 — Menu Bar (Standard Menu-Driven Program)

```java
import javax.swing.*;
import java.awt.event.*;

public class MenuDemo extends JFrame implements ActionListener {
    private JTextArea textArea;

    public MenuDemo() {
        setTitle("Menu Demo");
        setSize(400, 300);
        setDefaultCloseOperation(EXIT_ON_CLOSE);

        textArea = new JTextArea();
        add(new JScrollPane(textArea));

        // Create the menu bar
        JMenuBar menuBar = new JMenuBar();

        // File Menu
        JMenu fileMenu = new JMenu("File");
        JMenuItem newItem    = new JMenuItem("New");
        JMenuItem openItem   = new JMenuItem("Open");
        JMenuItem saveItem   = new JMenuItem("Save");
        JMenuItem exitItem   = new JMenuItem("Exit");
        fileMenu.add(newItem);
        fileMenu.add(openItem);
        fileMenu.add(saveItem);
        fileMenu.addSeparator();        // Visual divider line
        fileMenu.add(exitItem);

        // Edit Menu
        JMenu editMenu = new JMenu("Edit");
        editMenu.add(new JMenuItem("Cut"));
        editMenu.add(new JMenuItem("Copy"));
        editMenu.add(new JMenuItem("Paste"));

        // Help Menu
        JMenu helpMenu = new JMenu("Help");
        JMenuItem aboutItem = new JMenuItem("About");
        helpMenu.add(aboutItem);

        // Attach menus to the menubar
        menuBar.add(fileMenu);
        menuBar.add(editMenu);
        menuBar.add(helpMenu);

        // Attach the menubar to the frame
        setJMenuBar(menuBar);

        // Register listeners
        exitItem.addActionListener(this);
        aboutItem.addActionListener(this);
        newItem.addActionListener(this);

        setVisible(true);
    }

    @Override
    public void actionPerformed(ActionEvent e) {
        String cmd = e.getActionCommand();
        switch (cmd) {
            case "Exit": System.exit(0); break;
            case "About": 
                JOptionPane.showMessageDialog(this, "Menu Demo v1.0"); 
                break;
            case "New": 
                textArea.setText(""); 
                break;
        }
    }

    public static void main(String[] args) {
        SwingUtilities.invokeLater(() -> new MenuDemo());
    }
}
```

