## 3.1 Program 1 — Plain `JButton` with `ActionListener`

```java
import javax.swing.*;
import java.awt.*;
import java.awt.event.*;

public class ButtonDemo1 extends JFrame implements ActionListener {
    JButton b1, b2;
    JLabel result;

    ButtonDemo1() {
        setTitle("JButton Demo");
        setSize(300, 200);
        setLayout(new FlowLayout());
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);

        b1 = new JButton("Click Me");
        b2 = new JButton("Reset");
        result = new JLabel("Press a button");

        b1.addActionListener(this);   // Step 1: register listener
        b2.addActionListener(this);

        add(b1); add(b2); add(result);
        setVisible(true);
    }

    public void actionPerformed(ActionEvent e) {
        if (e.getSource() == b1)
            result.setText("You clicked Click Me");
        else if (e.getSource() == b2)
            result.setText("Reset done");
    }

    public static void main(String[] args) {
        new ButtonDemo1();
    }
}
```

### Line-by-Line Analytical Trace

| Step | Code | Explanation |
|---|---|---|
| 1 | `implements ActionListener` | Class *promises* to provide the `actionPerformed` method — a **callback contract**. |
| 2 | `b1.addActionListener(this)` | The button is given a reference to the current frame as its event handler. |
| 3 | `e.getSource() == b1` | Identifies *which* button triggered the event using reference equality. |
| 4 | `setDefaultCloseOperation(EXIT_ON_CLOSE)` | Ensures JVM terminates when window closes. |

## 3.2 Program 2 — `JCheckBox` with `ItemListener`

```java
import javax.swing.*;
import java.awt.*;
import java.awt.event.*;

public class CheckBoxDemo extends JFrame implements ItemListener {
    JCheckBox c1, c2, c3;
    JLabel order;

    CheckBoxDemo() {
        setTitle("Pizza Order");
        setSize(350, 200);
        setLayout(new FlowLayout());
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);

        order = new JLabel("Total: ₹0");
        c1 = new JCheckBox("Cheese  (₹100)");
        c2 = new JCheckBox("Olives  (₹50)");
        c3 = new JCheckBox("Mushroom (₹80)");

        c1.addItemListener(this);
        c2.addItemListener(this);
        c3.addItemListener(this);

        add(c1); add(c2); add(c3); add(order);
        setVisible(true);
    }

    public void itemStateChanged(ItemEvent e) {
        int total = 0;
        if (c1.isSelected()) total += 100;
        if (c2.isSelected()) total += 50;
        if (c3.isSelected()) total += 80;
        order.setText("Total: ₹" + total);
    }

    public static void main(String[] args) {
        new CheckBoxDemo();
    }
}
```

### Step-by-Step Logical Derivation

$$
\begin{aligned}
\text{Total} &= (\text{Cheese}_{sel} \times 100) + (\text{Olives}_{sel} \times 50) + (\text{Mushroom}_{sel} \times 80) \\[4pt]
\text{Where } \text{Cheese}_{sel} &= \begin{cases} 1, & \text{if } \text{c1.isSelected()} \\ 0, & \text{otherwise} \end{cases}
\end{aligned}
$$

> [!NOTE]
> Using **`if (c1.isSelected())`** inside the handler is more robust than checking `e.getStateChange() == ItemEvent.SELECTED` because the handler must compute the *sum* across all boxes after *each* individual state change. Both patterns are accepted by KTU examiners.

## 3.3 Program 3 — `JRadioButton` with `ButtonGroup`

```java
import javax.swing.*;
import java.awt.*;
import java.awt.event.*;

public class RadioDemo extends JFrame implements ActionListener {
    JRadioButton r1, r2, r3;
    ButtonGroup bg;
    JLabel display;

    RadioDemo() {
        setTitle("Transport Selector");
        setSize(300, 200);
        setLayout(new FlowLayout());
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);

        r1 = new JRadioButton("Car");
        r2 = new JRadioButton("Bus");
        r3 = new JRadioButton("Train");

        bg = new ButtonGroup();      // logical group
        bg.add(r1); bg.add(r2); bg.add(r3);   // enforce single selection

        r1.addActionListener(this);
        r2.addActionListener(this);
        r3.addActionListener(this);

        display = new JLabel("Choose a mode");

        add(r1); add(r2); add(r3); add(display);
        setVisible(true);
    }

    public void actionPerformed(ActionEvent e) {
        if (r1.isSelected()) display.setText("You chose Car");
        else if (r2.isSelected()) display.setText("You chose Bus");
        else if (r3.isSelected()) display.setText("You chose Train");
    }

    public static void main(String[] args) {
        new RadioDemo();
    }
}
```

### Analytical Trace

| Step | Why this line? |
|---|---|
| `ButtonGroup bg = new ButtonGroup();` | Creates a **logical** (invisible) group to enforce that at most one radio is selected. |
| `bg.add(r1); ...` | Adding radio buttons to the group auto-deselects siblings when one is clicked. |
| `add(r1); ...` | Note: we add the buttons themselves to the JFrame, **not** the `ButtonGroup` — `ButtonGroup` does not extend `Container`. |

## 3.4 Program 4 — Combining All Four Button Types

```java
import javax.swing.*;
import java.awt.*;
import java.awt.event.*;

public class CombinedDemo extends JFrame implements ActionListener, ItemListener {
    JButton submit;
    JToggleButton tgl;
    JCheckBox terms;
    JRadioButton male, female;
    ButtonGroup genderGroup;
    JLabel output;

    CombinedDemo() {
        setTitle("Registration Form");
        setSize(400, 300);
        setLayout(new GridLayout(7, 1));
        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);

        tgl  = new JToggleButton("Subscribe to Newsletter");
        terms = new JCheckBox("I accept the Terms");
        male = new JRadioButton("Male");
        female = new JRadioButton("Female");
        submit = new JButton("Submit");

        genderGroup = new ButtonGroup();
        genderGroup.add(male);
        genderGroup.add(female);

        tgl.addItemListener(this);
        terms.addItemListener(this);
        male.addActionListener(this);
        female.addActionListener(this);
        submit.addActionListener(this);

        output = new JLabel("Fill the form...");

        add(tgl); add(terms); add(male); add(female); add(submit); add(output);
        setVisible(true);
    }

    public void actionPerformed(ActionEvent e) {
        if (e.getSource() == submit) {
            String g = male.isSelected() ? "Male" : (female.isSelected() ? "Female" : "N/A");
            output.setText("Gender: " + g + " \vert Submitted!");
        } else {
            output.setText("Radio changed");
        }
    }

    public void itemStateChanged(ItemEvent e) {
        if (e.getSource() == tgl)
            output.setText("Newsletter: " + (tgl.isSelected() ? "ON" : "OFF"));
        else
            output.setText("Terms " + (terms.isSelected() ? "accepted" : "revoked"));
    }

    public static void main(String[] args) {
        new CombinedDemo();
    }
}
```

